import json
import angular from 'angular';

angular.module('dataGridApp', [])
.directive('dataGrid', function() {
    return {
        restrict: 'E',
        scope: {
            jsonData: '='
        },
        template: `
            <div>
                <input type="text" ng-model="searchText" placeholder="Search..." />
                <table>
                    <thead>
                        <tr>
                            <th ng-repeat="(key, value) in columns" ng-click="sortBy(key)">
                                {{ value }} <span ng-show="sortColumn === key">{{ sortDirection === 'asc' ? '▲' : '▼' }}</span>
                            </th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr ng-repeat="row in filteredData = (data | filter:searchText | orderBy:sortColumn:sortDirection === 'desc')">
                            <td ng-repeat="(key, value) in row">{{ value }}</td>
                        </tr>
                    </tbody>
                </table>
            </div>
        `,
        link: function(scope) {
            scope.$watch('jsonData', function(newVal) {
                if (newVal) {
                    const parsedData = JSON.parse(newVal);
                    scope.columns = parsedData.columns;
                    scope.data = parsedData.rows;
                    scope.sortColumn = '';
                    scope.sortDirection = 'asc';
                }
            });

            scope.sortBy = function(column) {
                scope.sortDirection = (scope.sortColumn === column && scope.sortDirection === 'asc') ? 'desc' : 'asc';
                scope.sortColumn = column;
            };
        }
    };
});
